import React, { useState, useEffect } from 'react';
import { View, Button, Text } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';

const CLIENT_ID = 'your_client_id';
const AUTHORIZATION_ENDPOINT = 'https://your-auth-server.com/auth';
const TOKEN_ENDPOINT = 'https://your-auth-server.com/token';
const REDIRECT_URI = AuthSession.makeRedirectUri({ useProxy: true });

const App = () => {
  const [authToken, setAuthToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  useEffect(() => {
    const checkStoredTokens = async () => {
      const storedAuthToken = await SecureStore.getItemAsync('authToken');
      const storedRefreshToken = await SecureStore.getItemAsync('refreshToken');
      if (storedAuthToken) setAuthToken(storedAuthToken);
      if (storedRefreshToken) setRefreshToken(storedRefreshToken);
    };
    checkStoredTokens();
  }, []);

  const handleAuth = async () => {
    const authUrl = `${AUTHORIZATION_ENDPOINT}?client_id=${CLIENT_ID}&response_type=code&redirect_uri=${encodeURIComponent(REDIRECT_URI)}`;
    const result = await AuthSession.startAsync({ authUrl });

    if (result.type === 'success') {
      const { code } = result.params;
      const tokenResponse = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&client_id=${CLIENT_ID}`,
      });

      const tokenData = await tokenResponse.json();
      setAuthToken(tokenData.access_token);
      setRefreshToken(tokenData.refresh_token);

      await SecureStore.setItemAsync('authToken', tokenData.access_token);
      await SecureStore.setItemAsync('refreshToken', tokenData.refresh_token);
    }
  };

  const refreshAuthToken = async () => {
    if (!refreshToken) return;

    const tokenResponse = await fetch(TOKEN_ENDPOINT, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `grant_type=refresh_token&refresh_token=${refreshToken}&client_id=${CLIENT_ID}`,
    });

    const tokenData = await tokenResponse.json();
    setAuthToken(tokenData.access_token);

    await SecureStore.setItemAsync('authToken', tokenData.access_token);
  };

  return (
    <View>
      <Button title="Authenticate" onPress={handleAuth} />
      {authToken && <Text>Authenticated</Text>}
      <Button title="Refresh Token" onPress={refreshAuthToken} />
    </View>
  );
};

export default App;